\begin{align*} S - \frac{1}{3} S &= \frac{1}{3} + \frac{2}{3^2} + \frac{3}{3^3} + \cdots + \frac{k}{3^k} + \cdots \\   &= \frac{S}{3} + \left( \frac{2}{3^2} - \frac{1}{3} \right) + \left( \frac{3}{3^3} - \frac{2}{3^2} \right) + \cdots \\   &= \frac{S}{3} + \frac{3}{3^3} - \frac{1}{3^2} + \frac{3}{3^3} - \frac{2}{3^3} + \cdots  \\   &= \frac{S}{3} + \left ( \frac{1}{3^2} + \frac{1}{3^3} + \frac{1}{3^4} + \cdots \right ) -  \frac{1}{3^2} \\   &= \frac{S}{3} + \frac{\frac{1}{3^2}}{1 - \frac{1}{3}} -  \frac{1}{3^2} \\   \frac{2}{3} S  &= \frac{\frac{1}{3^2}}{\frac{2}{3}} -  \frac{1}{3^2} \\  S &= \frac{\frac{1}{3}}{2} -  \frac{1}{3^2} \\   &= \frac{1}{6} \).  <answer> \(\boxed{0.16\overline{6}} \ \boxed{\frac{1}{6}} \end{align*} 
